// Auto-extracted inline <script> blocks from playground.html.
// SOURCE OF TRUTH remains the inline blocks; this sidecar is for
// auditor convenience + future CSP nonce/hash migration. Do NOT
// load this file directly — the inline blocks are still authoritative.
// Generated by scripts/cwv_hardening_patch.py — do not hand-edit.

/* ----------------------------------------------------------------------
    Quick Wizard: v2 wizard controller. Vanilla JS, no framework.
    ---------------------------------------------------------------------- */
 (function () {
   'use strict';
   var API_BASE = (window.JPCITE_API_BASE || 'https://api.jpcite.com').replace(/\/$/, '');

   var step1 = document.getElementById('v2-step-1');
   var step2 = document.getElementById('v2-step-2');
   var step3 = document.getElementById('v2-step-3');
   if (!step1 || !step2 || !step3) return;

   var authAnon = document.getElementById('v2-auth-anon');
   var authKey  = document.getElementById('v2-auth-key');
   var keyInput = document.getElementById('v2-api-key');
   var keyWrap  = document.getElementById('v2-key-input-wrap');
   var nextBtn  = document.getElementById('v2-step-1-next');

   var toolSel  = document.getElementById('v2-tool');
   var queryEl  = document.getElementById('v2-query');
   var runBtn   = document.getElementById('v2-run');
   var statusEl = document.getElementById('v2-status');

   var tbody    = document.getElementById('v2-result-tbody');
   var snippetEl = document.getElementById('v2-snippet');
   var copyBtn  = document.getElementById('v2-copy');
   var copyStat = document.getElementById('v2-copy-status');

   var tabCurl   = document.getElementById('v2-tab-curl');
   var tabPython = document.getElementById('v2-tab-python');
   var tabSdk    = document.getElementById('v2-tab-sdk');

   var snippetKind = 'curl';     // current code-example kind
   var lastQuery = null;          // last (tool, query) executed
   var lastTool = null;

   /* Step 1 → enable key input on radio toggle. */
   authAnon.addEventListener('change', function () { keyWrap.hidden = true; });
   authKey.addEventListener('change',  function () { keyWrap.hidden = false; keyInput.focus(); });

   nextBtn.addEventListener('click', function () {
     /* unlock step 2 */
     step2.style.opacity = '1';
     step2.dataset.state = 'active';
     toolSel.disabled = false;
     queryEl.disabled = false;
     runBtn.disabled  = false;
     queryEl.focus();
   });

   /* Step 2 → SSE run.
      We POST to /v1/search/stream?tool=...&q=... with EventSource.
      Since EventSource only supports GET, the API consumes query params. */
   runBtn.addEventListener('click', function () {
     var q = (queryEl.value || '').trim();
     if (!q) { statusEl.textContent = 'query が空です'; return; }
     lastQuery = q;
     lastTool  = toolSel.value;
     statusEl.textContent = '接続中…';
     runBtn.disabled = true;

     var url = API_BASE + '/v1/search/stream'
         + '?tool=' + encodeURIComponent(lastTool)
         + '&q='    + encodeURIComponent(q);

     var es;
     try {
       /* EventSource cannot set custom auth headers in browser. The
          /v1/search/stream endpoint accepts `?api_key=` as a fallback
          for SSE, OR a session cookie set via login. For wizard simplicity
          we pass api_key over the wire iff user explicitly chose key mode. */
       if (authKey.checked && keyInput.value) {
         url += '&api_key=' + encodeURIComponent(keyInput.value);
       }
       es = new EventSource(url);
     } catch (err) {
       statusEl.textContent = 'EventSource 起動失敗: ' + err.message;
       runBtn.disabled = false;
       return;
     }

     /* result rows arrive as message events, each carrying a single
        row JSON. The server emits a final `event: done` to signal
        completion. */
     var rows = [];
     es.addEventListener('message', function (ev) {
       try {
         var payload = JSON.parse(ev.data);
         if (Array.isArray(payload.rows)) {
           rows = rows.concat(payload.rows);
         } else if (payload.row) {
           rows.push(payload.row);
         }
         renderRows(rows);
       } catch (err) { /* skip malformed chunk */ }
     });
     es.addEventListener('done', function () {
       statusEl.textContent = '完了 (' + rows.length + ' 件)';
       es.close();
       runBtn.disabled = false;
       unlockStep3();
     });
     es.addEventListener('error', function () {
       statusEl.textContent = 'SSE error (接続切断)';
       try { es.close(); } catch (_) {}
       runBtn.disabled = false;
       /* Even on partial error, unlock step 3 with whatever rows we got
          plus the code-example panel — the most important thing for
          the user is the runnable snippet. */
       unlockStep3();
     });
   });

   function renderRows(rows) {
     tbody.innerHTML = '';
     if (!rows.length) {
       var tr = document.createElement('tr');
       tr.innerHTML = '<td colspan="3" style="padding:12px;color:var(--text-muted);text-align:center;">結果なし</td>';
       tbody.appendChild(tr);
       return;
     }
     rows.slice(0, 20).forEach(function (r, i) {
       var tr = document.createElement('tr');
       tr.innerHTML =
         '<td style="padding:6px 8px;border-bottom:1px solid var(--border);">' + (i + 1) + '</td>' +
         '<td style="padding:6px 8px;border-bottom:1px solid var(--border);">' + escapeHtml(r.title || r.name || r.id || '(no title)') + '</td>' +
         '<td style="padding:6px 8px;border-bottom:1px solid var(--border);"><a href="' + escapeAttr(r.source_url || '#') + '" target="_blank" rel="noopener">source →</a></td>';
       tbody.appendChild(tr);
     });
   }

   function unlockStep3() {
     step3.style.opacity = '1';
     step3.dataset.state = 'active';
     renderSnippet();
   }

   function renderSnippet() {
     if (!lastTool || lastQuery === null) {
       snippetEl.textContent = '# step 2 を実行するとここにコード例が表示されます\n';
       return;
     }
     if (snippetKind === 'curl') snippetEl.textContent = curlSnippet(lastTool, lastQuery);
     else if (snippetKind === 'python') snippetEl.textContent = pythonSnippet(lastTool, lastQuery);
     else snippetEl.textContent = sdkSnippet(lastTool, lastQuery);
   }

   function curlSnippet(tool, q) {
     var hdr = authKey.checked && keyInput.value
       ? '\\\n  -H "X-API-Key: ' + maskKey(keyInput.value) + '"'
       : '';
     return 'curl -N "' + API_BASE + '/v1/search/stream'
       + '?tool=' + encodeURIComponent(tool)
       + '&q=' + encodeURIComponent(q) + '" ' + hdr;
   }

   function pythonSnippet(tool, q) {
     var keyLine = authKey.checked && keyInput.value
       ? '\nHEADERS = {"X-API-Key": "' + maskKey(keyInput.value) + '"}'
       : '\nHEADERS = {}';
     return [
       'import httpx',
       keyLine,
       '',
       'with httpx.stream("GET",',
       '    "' + API_BASE + '/v1/search/stream",',
       '    params={"tool": "' + tool + '", "q": "' + q + '"},',
       '    headers=HEADERS, timeout=30.0) as r:',
       '    for line in r.iter_lines():',
       '        if line.startswith("data: "):',
       '            print(line[6:])',
     ].join('\n');
   }

   function sdkSnippet(tool, q) {
     return [
       'import { JpciteClient } from "@jpcite/sdk";',
       '',
       'const client = new JpciteClient({',
       '  apiKey: ' + (authKey.checked && keyInput.value ? '"' + maskKey(keyInput.value) + '"' : 'undefined') + ',  // undefined = anonymous',
       '});',
       '',
       'for await (const row of client.searchStream({ tool: "' + tool + '", q: "' + q + '" })) {',
       '  console.log(row.title, row.source_url);',
       '}',
     ].join('\n');
   }

   function maskKey(k) {
     /* Show first 4 + last 2 of the key so the copied snippet works on
        a hand-edit but does not paste the full key into a screenshot. */
     if (!k || k.length < 10) return 'jc_xxx';
     return k.substring(0, 4) + '...' + k.substring(k.length - 2);
   }

   /* Tab switch (curl / python / sdk) */
   [tabCurl, tabPython, tabSdk].forEach(function (btn) {
     btn.addEventListener('click', function () {
       snippetKind = btn.dataset.snippet;
       [tabCurl, tabPython, tabSdk].forEach(function (b) {
         b.setAttribute('aria-selected', String(b === btn));
         b.style.borderBottom = (b === btn) ? '2px solid var(--accent)' : '2px solid transparent';
       });
       renderSnippet();
     });
   });

   copyBtn.addEventListener('click', function () {
     var txt = snippetEl.textContent || '';
     if (!txt) return;
     try {
       navigator.clipboard.writeText(txt).then(function () {
         copyStat.textContent = 'コピーしました';
         setTimeout(function () { copyStat.textContent = ''; }, 3000);
       });
     } catch (err) {
       copyStat.textContent = 'コピー失敗: ' + err.message;
     }
   });

   function escapeHtml(s) {
     return String(s == null ? '' : s)
       .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
       .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
   }
   function escapeAttr(s) { return escapeHtml(s); }
 })();
